async function registerBookingForwardRoutes(app2, options) {
  const { db } = options;
  const ingestionService = new BookingIngestionService(db);
  app2.post(
    "/api/bookings/forward",
    {
      config: {
        rateLimit: {
          max: 30,
          timeWindow: "1 minute"
        }
      }
    },
    async (request, reply) => {
      const { from, subject, htmlBody, textBody } = request.body ?? {};
      if (!from || !subject) {
        return reply.status(400).send({
          statusCode: 400,
          error: "VALIDATION_ERROR",
          message: '"from" and "subject" are required fields'
        });
      }
      if (!htmlBody && !textBody) {
        return reply.status(400).send({
          statusCode: 400,
          error: "VALIDATION_ERROR",
          message: 'At least one of "htmlBody" or "textBody" must be provided'
        });
      }
      try {
        const extracted = await parseBookingEmail({
          from,
          subject,
          htmlBody: htmlBody ?? "",
          textBody: textBody ?? ""
        });
        if (!extracted) {
          return reply.status(422).send({
            statusCode: 422,
            error: "EXTRACTION_FAILED",
            message: "Could not extract booking details from this email. Make sure it's a booking confirmation."
          });
        }
        const result = await ingestionService.processForwardedBooking(from, extracted);
        const statusCode = result.status === "error" ? 500 : result.status === "pending_user_signup" ? 202 : 200;
        return reply.status(statusCode).send({
          statusCode,
          data: result
        });
      } catch (error51) {
        request.log.error(error51, "Booking forward processing failed");
        return reply.status(500).send({
          statusCode: 500,
          error: "INTERNAL_ERROR",
          message: "Failed to process the forwarded booking"
        });
      }
    }
  );
  app2.post(
    "/api/bookings/claim/:token",
    async (request, reply) => {
      const userId = request.userId;
      const { token } = request.params;
      if (!userId || userId === "dev-user") {
        return reply.status(401).send({
          statusCode: 401,
          error: "UNAUTHORIZED",
          message: "You must be logged in to claim a booking"
        });
      }
      const result = await ingestionService.claimByToken(userId, token);
      if (result.status === "error") {
        return reply.status(400).send({ statusCode: 400, ...result });
      }
      return reply.send({ statusCode: 200, data: result });
    }
  );
  app2.get(
    "/api/bookings/unclaimed",
    async (request, reply) => {
      const userId = request.userId;
      if (!userId || userId === "dev-user") {
        return reply.status(401).send({
          statusCode: 401,
          error: "UNAUTHORIZED",
          message: "Authentication required"
        });
      }
      const user = await db.selectFrom("users").select("email").where("id", "=", userId).executeTakeFirst();
      if (!user) {
        return reply.status(404).send({ statusCode: 404, error: "User not found" });
      }
      const unclaimed = await db.selectFrom("unclaimed_bookings").select(["id", "booking_type", "destination", "start_date", "end_date", "created_at", "expires_at"]).where("email", "=", user.email).where("claimed", "=", false).where("expires_at", ">", /* @__PURE__ */ new Date()).orderBy("created_at", "desc").execute();
      return reply.send({
        statusCode: 200,
        data: {
          count: unclaimed.length,
          bookings: unclaimed,
          autoClaimAvailable: unclaimed.length > 0
        }
      });
    }
  );
  app2.post(
    "/api/bookings/claim-all",
    async (request, reply) => {
      const userId = request.userId;
      if (!userId || userId === "dev-user") {
        return reply.status(401).send({
          statusCode: 401,
          error: "UNAUTHORIZED",
          message: "Authentication required"
        });
      }
      const user = await db.selectFrom("users").select("email").where("id", "=", userId).executeTakeFirst();
      if (!user) {
        return reply.status(404).send({ statusCode: 404, error: "User not found" });
      }
      const claimedCount = await ingestionService.claimBookingsForUser(userId, user.email);
      return reply.send({
        statusCode: 200,
        data: {
          claimedCount,
          message: claimedCount > 0 ? `${claimedCount} booking(s) have been added to your account!` : "No unclaimed bookings found for your email."
        }
      });
    }
  );
}
