// packages/api/src/plugins/admin-auth.ts
import fp4 from "fastify-plugin";
async function adminAuthPlugin(app2, options) {
  const { db } = options;
  app2.decorate("requireAdmin", async (request, reply) => {
    const userId = request.userId;
    if (!userId) {
      return reply.status(401).send({
        statusCode: 401,
        error: "UNAUTHORIZED",
        message: "Authentication required"
      });
    }
    const user = await db.selectFrom("users").select(["id", "admin_role", "suspended"]).where("id", "=", userId).executeTakeFirst();
    if (!user) {
      return reply.status(401).send({
        statusCode: 401,
        error: "UNAUTHORIZED",
        message: "User not found"
      });
    }
    if (user.suspended) {
      return reply.status(403).send({
        statusCode: 403,
        error: "SUSPENDED",
        message: "Your account has been suspended. Contact support@neyya.ai for assistance."
      });
    }
    const role = user.admin_role;
    if (!role || role !== "super-admin" && role !== "support") {
      return reply.status(403).send({
        statusCode: 403,
        error: "FORBIDDEN",
        message: "Admin access required"
      });
    }
    request.adminRole = role;
    request.isAdmin = true;
  });
  app2.decorate("requireSuperAdmin", async (request, reply) => {
    const userId = request.userId;
    if (!userId) {
      return reply.status(401).send({ statusCode: 401, error: "UNAUTHORIZED", message: "Authentication required" });
    }
    const user = await db.selectFrom("users").select(["id", "admin_role", "suspended"]).where("id", "=", userId).executeTakeFirst();
    if (!user || user.suspended) {
      return reply.status(403).send({ statusCode: 403, error: "FORBIDDEN", message: "Access denied" });
    }
    if (user.admin_role !== "super-admin") {
      return reply.status(403).send({
        statusCode: 403,
        error: "FORBIDDEN",
        message: "Super-admin access required for this operation"
      });
    }
    request.adminRole = "super-admin";
    request.isAdmin = true;
  });
}
var registerAdminAuth = fp4(adminAuthPlugin, {
  name: "admin-auth"
});

