function validateExpense(body) {
  const errors = [];
  if (!body.amount || body.amount < 0.01 || body.amount > 99999999999e-2) {
    errors.push("amount must be between 0.01 and 999,999,999.99");
  }
  if (!body.currency || body.currency.length !== 3) {
    errors.push("currency must be a 3-letter ISO 4217 code");
  }
  if (!body.category || !EXPENSE_CATEGORIES2.includes(body.category)) {
    errors.push(`category must be one of: ${EXPENSE_CATEGORIES2.join(", ")}`);
  }
  if (!body.date || !/^\d{4}-\d{2}-\d{2}/.test(body.date)) {
    errors.push("date must be a valid ISO date (YYYY-MM-DD)");
  }
  if (body.notes && body.notes.length > 500) {
    errors.push("notes must be at most 500 characters");
  }
  return errors;
}
async function checkBudgetThresholds(db, tripId, userId) {
  const trip = await db.selectFrom("trips").select(["budget", "budget_currency", "budget_alert_80", "budget_alert_100"]).where("id", "=", tripId).executeTakeFirst();
  if (!trip?.budget) return;
  const expenses = await db.selectFrom("expenses").select("converted_amount").where("trip_id", "=", tripId).where("user_id", "=", userId).execute();
  const totalSpent = expenses.reduce(
    (sum, e) => sum + (e.converted_amount ?? 0),
    0
  );
  const percentUsed = totalSpent / trip.budget * 100;
  if (percentUsed >= 80 && percentUsed < 100 && !trip.budget_alert_80) {
    await db.updateTable("trips").set({ budget_alert_80: true }).where("id", "=", tripId).execute();
    console.log(`[Budget] 80% threshold reached for trip ${tripId}`);
  } else if (percentUsed < 80 && trip.budget_alert_80) {
    await db.updateTable("trips").set({ budget_alert_80: false }).where("id", "=", tripId).execute();
  }
  if (percentUsed >= 100 && !trip.budget_alert_100) {
    await db.updateTable("trips").set({ budget_alert_100: true }).where("id", "=", tripId).execute();
    console.log(`[Budget] 100% threshold exceeded for trip ${tripId}`);
  } else if (percentUsed < 100 && trip.budget_alert_100) {
    await db.updateTable("trips").set({ budget_alert_100: false }).where("id", "=", tripId).execute();
  }
}
function generateCsv(expenses) {
  const header = "Date,Merchant,Category,Amount,Currency,Converted Amount,Home Currency\n";
  const rows = expenses.map(
    (e) => `${e.date},"${e.merchant_name ?? ""}",${e.category},${e.amount},${e.currency},${e.converted_amount ?? ""},${e.home_currency ?? "USD"}`
  ).join("\n");
  return header + rows;
}
function generatePdfPlaceholder(expenses, tripId) {
  return `%PDF-1.4
% Expense Report for Trip ${tripId}
% ${expenses.length} expenses
% This is a placeholder. Use PDFKit in production.`;
}

