async function registerAdminTripMembershipRoutes(app2, options) {
  const { db } = options;
  app2.get("/api/admin/trip-memberships", async (_request, reply) => {
    const totalTravellers = await db.selectFrom("trip_travellers").select(db.fn.count("id").as("count")).executeTakeFirst();
    const activeTravellers = await db.selectFrom("trip_travellers").select(db.fn.count("id").as("count")).where("status", "=", "active").executeTakeFirst();
    const pendingInvitations = await db.selectFrom("trip_invitations").select(db.fn.count("id").as("count")).where("status", "=", "pending").executeTakeFirst();
    const tripsWithMembers = await db.selectFrom("trip_travellers").select("trip_id").groupBy("trip_id").execute();
    const avgPerTrip = tripsWithMembers.length > 0 ? Math.round(Number(totalTravellers?.count ?? 0) / tripsWithMembers.length) : 0;
    const byType = await db.selectFrom("trip_travellers").select(["traveller_type as type", db.fn.count("id").as("count")]).groupBy("traveller_type").execute();
    const byRole = await db.selectFrom("trip_travellers").select(["role", db.fn.count("id").as("count")]).groupBy("role").execute();
    const groups = await db.selectFrom("trip_groups").selectAll().execute();
    const groupsWithCounts = await Promise.all(groups.map(async (g) => {
      const memberCount = await db.selectFrom("trip_travellers").select(db.fn.count("id").as("count")).where("group_id", "=", g.id).executeTakeFirst();
      return { ...g, member_count: Number(memberCount?.count ?? 0) };
    }));
    return reply.send({
      statusCode: 200,
      data: {
        totalTravellers: Number(totalTravellers?.count ?? 0),
        activeTravellers: Number(activeTravellers?.count ?? 0),
        pendingInvitations: Number(pendingInvitations?.count ?? 0),
        avgPerTrip,
        totalGroups: groups.length,
        byType: byType.map((t) => ({ type: t.type, count: Number(t.count) })),
        byRole: byRole.map((r) => ({ role: r.role, count: Number(r.count) })),
        groups: groupsWithCounts
      }
    });
  });
}

// packages/api/src/routes/documents.ts
import { S3Client, PutObjectCommand, DeleteObjectCommand, GetObjectCommand } from "@aws-sdk/client-s3";
import { getSignedUrl } from "@aws-sdk/s3-request-presigner";
var DOCUMENT_CATEGORIES = [
  "boarding_pass",
  "confirmation",
  "voucher",
  "visa",
  "insurance",
  "other"
];
var ALLOWED_MIME_TYPES = [
  "application/pdf",
  "image/jpeg",
  "image/png",
  "image/heic"
];
var MAX_FILE_SIZE = 25 * 1024 * 1024;
var MAX_DOCUMENTS_PER_TRIP = 100;
async function registerDocumentRoutes(app2, options) {
  const { db, s3Bucket, s3Region, cloudfrontDomain } = options;
  const s3Client = new S3Client({ region: s3Region });
  app2.post(
    "/api/documents/upload",
    async (request, reply) => {
      const userId = request.userId;
      const { tripId, category, filename, mimeType, fileContent, bookingId } = request.body;
      if (!ALLOWED_MIME_TYPES.includes(mimeType)) {
        return reply.status(400).send({
          statusCode: 400,
          error: "VALIDATION_ERROR",
          message: `Unsupported file type. Allowed: ${ALLOWED_MIME_TYPES.join(", ")}`
        });
      }
      if (!DOCUMENT_CATEGORIES.includes(category)) {
        return reply.status(400).send({
          statusCode: 400,
          error: "VALIDATION_ERROR",
          message: `Invalid category. Allowed: ${DOCUMENT_CATEGORIES.join(", ")}`
        });
      }
      const buffer = Buffer.from(fileContent, "base64");
      if (buffer.length > MAX_FILE_SIZE) {
        return reply.status(400).send({
          statusCode: 400,
          error: "VALIDATION_ERROR",
          message: `File too large. Maximum size is 25MB.`
        });
      }
      const existingCount = await db.selectFrom("documents").select(db.fn.count("id").as("count")).where("trip_id", "=", tripId).executeTakeFirst();
      if (Number(existingCount?.count ?? 0) >= MAX_DOCUMENTS_PER_TRIP) {
        return reply.status(400).send({
          statusCode: 400,
          error: "LIMIT_EXCEEDED",
          message: `Maximum ${MAX_DOCUMENTS_PER_TRIP} documents per trip`
        });
      }
      try {
        const s3Key = `documents/${userId}/${tripId}/${Date.now()}-${filename}`;
        await s3Client.send(
          new PutObjectCommand({
            Bucket: s3Bucket,
            Key: s3Key,
            Body: buffer,
            ContentType: mimeType,
            Metadata: {
              userId,
              tripId,
              category
            }
          })
        );
        const doc = await db.insertInto("documents").values({
          user_id: userId,
          trip_id: tripId,
          booking_id: bookingId ?? null,
          category,
          filename,
          mime_type: mimeType,
          file_size: buffer.length,
          s3_key: s3Key,
          s3_bucket: s3Bucket
        }).returning(["id", "filename", "category", "file_size", "created_at"]).executeTakeFirstOrThrow();
        const url2 = cloudfrontDomain ? `https://${cloudfrontDomain}/${s3Key}` : await getSignedUrl(
          s3Client,
          new GetObjectCommand({ Bucket: s3Bucket, Key: s3Key }),
          { expiresIn: 3600 }
        );
        return reply.status(201).send({
          statusCode: 201,
          data: {
            ...doc,
            url: url2
          }
        });
      } catch (error51) {
        request.log.error(error51, "Failed to upload document");
        return reply.status(500).send({
          statusCode: 500,
          error: "INTERNAL_ERROR",
          message: "Failed to upload document"
        });
      }
    }
  );
  app2.get(
    "/api/trips/:tripId/documents",
    async (request, reply) => {
      const userId = request.userId;
      const { tripId } = request.params;
      const { category } = request.query;
      let query = db.selectFrom("documents").selectAll().where("trip_id", "=", tripId).where("user_id", "=", userId).orderBy("created_at", "desc");
      if (category && DOCUMENT_CATEGORIES.includes(category)) {
        query = query.where("category", "=", category);
      }
      const documents = await query.execute();
      const docsWithUrls = await Promise.all(
        documents.map(async (doc) => {
          const url2 = cloudfrontDomain ? `https://${cloudfrontDomain}/${doc.s3_key}` : await getSignedUrl(
            s3Client,
            new GetObjectCommand({ Bucket: doc.s3_bucket, Key: doc.s3_key }),
            { expiresIn: 3600 }
          );
          return { ...doc, url: url2 };
        })
      );
      return reply.send({ statusCode: 200, data: docsWithUrls });
    }
  );
  app2.delete(
    "/api/documents/:documentId",
    async (request, reply) => {
      const userId = request.userId;
      const { documentId } = request.params;
      const doc = await db.selectFrom("documents").select(["id", "s3_key", "s3_bucket"]).where("id", "=", documentId).where("user_id", "=", userId).executeTakeFirst();
      if (!doc) {
        return reply.status(404).send({
          statusCode: 404,
          error: "NOT_FOUND",
          message: "Document not found"
        });
      }
      try {
        await s3Client.send(
          new DeleteObjectCommand({
            Bucket: doc.s3_bucket,
            Key: doc.s3_key
          })
        );
      } catch (error51) {
        request.log.warn(error51, "Failed to delete S3 object (continuing with DB delete)");
      }
      await db.deleteFrom("documents").where("id", "=", documentId).execute();
      return reply.send({ statusCode: 200, message: "Document deleted" });
    }
  );
}

