      if (!connection) {
        return reply.status(403).send({ statusCode: 403, error: "FORBIDDEN", message: "You are not connected to this user" });
      }
      const members = await db.selectFrom("family_members").selectAll().where("user_id", "=", targetUserId).where("visibility_to_connections", "=", "connections").orderBy("relationship", "asc").execute();
