function generateAiChatResponse(question, context) {
  const lower = question.toLowerCase();
  if (lower.includes("restaurant") || lower.includes("food") || lower.includes("eat")) {
    return `\u{1F916} Based on your trip to **${context}**, here are some restaurant suggestions:

1. \u{1F37D}\uFE0F Try local cuisine at highly-rated spots near your hotel
2. \u{1F37D}\uFE0F Book popular restaurants 1-2 weeks ahead
3. \u{1F37D}\uFE0F Lunch menus are usually 30-40% cheaper than dinner

_Mark this as a Trip Decision if the group agrees!_`;
  }
  if (lower.includes("activit") || lower.includes("do") || lower.includes("visit")) {
    return `\u{1F916} Here are top activities for **${context}**:

1. \u{1F3AF} Visit the main historical attractions (book online for skip-the-line)
2. \u{1F3AF} Take a guided walking tour on Day 1
3. \u{1F3AF} Reserve a day trip for nearby highlights

_Vote on which activities the group wants to do!_`;
  }
  if (lower.includes("hotel") || lower.includes("stay") || lower.includes("accommodation")) {
    return `\u{1F916} For accommodation in **${context}**:

- Central location saves transport time and money
- Book with free cancellation for flexibility
- Check reviews from the last 3 months

_Create a poll to vote on which hotel the group prefers!_`;
  }
  return `\u{1F916} Great question about **${context}**! Here's my suggestion:

I'd recommend researching this together as a group. You can:
- \u{1F4CA} Create a **poll** to vote on options
- \u2705 Mark the best answer as a **Trip Decision**
- \u2B50 Save it to your trip **Favorites**

_Everyone in this chat can vote and contribute!_`;
}

