import { sql as sql8 } from "kysely";
async function registerAnalyticsRoutes(app2, options) {
  const { db } = options;
  app2.post("/api/analytics/event", async (request, reply) => {
    const userId = request.userId ?? null;
    const { eventType, page, element, metadata, sessionId } = request.body;
    if (!eventType) return reply.status(400).send({ statusCode: 400, error: "eventType required" });
    await db.insertInto("analytics_events").values({
      user_id: userId,
      session_id: sessionId ?? null,
      event_type: eventType,
      page: page ?? null,
      element: element ?? null,
      metadata: metadata ? JSON.stringify(metadata) : null
    }).execute();
    return reply.send({ statusCode: 200, tracked: true });
  });
  app2.post("/api/analytics/batch", async (request, reply) => {
    const userId = request.userId ?? null;
    const { events } = request.body;
    if (!Array.isArray(events) || events.length === 0) return reply.status(400).send({ statusCode: 400, error: "events array required" });
    for (const evt of events.slice(0, 50)) {
      await db.insertInto("analytics_events").values({
        user_id: userId,
        session_id: evt.sessionId ?? null,
        event_type: evt.eventType ?? "unknown",
        page: evt.page ?? null,
        element: evt.element ?? null,
        metadata: evt.metadata ? JSON.stringify(evt.metadata) : null
      }).execute();
    }
    return reply.send({ statusCode: 200, tracked: events.length });
  });
  app2.get("/api/admin/analytics", async (_request, reply) => {
    const totalEvents = await db.selectFrom("analytics_events").select(sql8`count(*)`.as("count")).executeTakeFirst();
    const today = await db.selectFrom("analytics_events").select(sql8`count(*)`.as("count")).where("created_at", ">=", sql8`now() - interval '24 hours'`).executeTakeFirst();
    const uniqueUsers = await db.selectFrom("analytics_events").select(sql8`count(distinct user_id)`.as("count")).where("created_at", ">=", sql8`now() - interval '7 days'`).executeTakeFirst();
    const topPages = await db.selectFrom("analytics_events").select(["page", sql8`count(*)`.as("views")]).where("event_type", "=", "page_view").where("page", "is not", null).groupBy("page").orderBy(sql8`count(*)`, "desc").limit(10).execute();
    const topFeatures = await db.selectFrom("analytics_events").select(["element", sql8`count(*)`.as("uses")]).where("event_type", "=", "feature_use").where("element", "is not", null).groupBy("element").orderBy(sql8`count(*)`, "desc").limit(10).execute();
    const eventsByDay = await db.selectFrom("analytics_events").select([sql8`date(created_at)`.as("day"), sql8`count(*)`.as("count")]).where("created_at", ">=", sql8`now() - interval '30 days'`).groupBy(sql8`date(created_at)`).orderBy(sql8`date(created_at)`, "desc").limit(30).execute();
    return reply.send({
      statusCode: 200,
      data: {
        totalEvents: totalEvents?.count ?? 0,
        eventsToday: today?.count ?? 0,
        uniqueUsersWeek: uniqueUsers?.count ?? 0,
        topPages,
        topFeatures,
        eventsByDay
      }
    });
  });
}

