async function registerActivityFeedRoutes(app2, options) {
  const { db } = options;
  app2.get(
    "/api/trips/:tripId/activity-feed",
    { preHandler: [app2.requireAuth] },
    async (request, reply) => {
      const { tripId } = request.params;
      const userId = request.user.userId;
      const rawLimit = request.query.limit;
      let limit = 50;
      if (rawLimit !== void 0) {
        const parsed = parseInt(rawLimit, 10);
        if (isNaN(parsed) || parsed < 1) {
          return reply.status(400).send({
            statusCode: 400,
            error: "VALIDATION_ERROR",
            message: "limit must be a positive integer"
          });
        }
        limit = Math.min(parsed, 50);
      }
      try {
        const trip = await db.selectFrom("trips").select(["id", "owner_id"]).where("id", "=", tripId).executeTakeFirst();
        if (!trip) {
          return reply.status(404).send({
            statusCode: 404,
            error: "NOT_FOUND",
            message: "Trip not found"
          });
        }
        if (trip.owner_id !== userId) {
          const membership = await db.selectFrom("trip_members").select("id").where("trip_id", "=", tripId).where("user_id", "=", userId).executeTakeFirst();
          if (!membership) {
            return reply.status(403).send({
              statusCode: 403,
              error: "FORBIDDEN",
              message: "You do not have access to this trip"
            });
          }
        }
        const entries = await db.selectFrom("activity_feed").innerJoin("users", "users.id", "activity_feed.user_id").select([
          "activity_feed.id",
          "activity_feed.user_id as userId",
          "users.display_name as userName",
          "activity_feed.action",
          "activity_feed.entity_type as entityType",
          "activity_feed.entity_id as entityId",
          "activity_feed.metadata",
          "activity_feed.created_at as timestamp"
        ]).where("activity_feed.trip_id", "=", tripId).orderBy("activity_feed.created_at", "desc").limit(limit).execute();
        return reply.status(200).send(entries);
      } catch (error51) {
        request.log.error(error51, "Failed to fetch activity feed");
        return reply.status(500).send({
          statusCode: 500,
          error: "INTERNAL_ERROR",
          message: "An unexpected error occurred while fetching the activity feed"
        });
      }
    }
  );
}

